#include "http_rest_api.h"
#include <WiFi.h>
#include <HTTPClient.h>
static int _code=0;
void rest_setup(){Serial.println("[rest] OK");}
String rest_get(const char*url){HTTPClient http;http.begin(url);_code=http.GET();String r=http.getString();http.end();return r;}
String rest_post(const char*url,const char*json){HTTPClient http;http.begin(url);http.addHeader("Content-Type","application/json");_code=http.POST(json);String r=http.getString();http.end();return r;}
int rest_last_code(){return _code;}
